import{_ as t,o as a,c as o,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Basic Postback Configuration","description":"","frontmatter":{"title":"Basic Postback Configuration","slug":"basic-postback-configuration"},"headers":[],"relativePath":"marketer-hub/basic-postback-configuration.md","filePath":"marketer-hub/basic-postback-configuration.md"}'),r={name:"marketer-hub/basic-postback-configuration.md"};function n(i,e,l,c,p,d){return a(),o("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>When Branch measures a conversion (install or other event), it determines which ad network or partner is responsible for generating the action, then attributes credit to the proper partner accordingly. Branch notifies partners of these events via Postbacks which are turned on when you enable any Ads integrated partner.</p><p>Branch’s postback system is highly customizable; set up postbacks for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>Ads partners support pre-defined postback templates to simplify the generation of the proper postback URL. If they require any additional information (such as an event-specific Goal ID), Branch displays empty fields for you to input that information that are automatically appended to the postback URL.</p><h2 id="add-postbacks" tabindex="-1">Add postbacks <a class="header-anchor" href="#add-postbacks" aria-label="Permalink to &quot;Add postbacks&quot;">​</a></h2><p>Basic postbacks are automatically activated for events like <strong>INSTALL</strong> and <strong>PURCHASE</strong> when you enable your ad partner. You can then add additional postbacks, for example, if you wanted to add postbacks for custom events that are specific to your app like <strong>Account Created</strong>.</p><p>To add a postback:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</li><li>Click on the <strong>Postback Config</strong> tab on said partner’s page.</li><li>Click the <strong>Add New Postback</strong> button at the bottom of the screen.</li><li>A modal will appear with Branch default events, as well as any commerce (reserved events like <strong>PURCHASE</strong>) or custom events you&#39;ve set up.</li><li>Click <strong>Save</strong>.</li></ol><p><em>[Image: 885]</em></p><p>In some cases, you will also be prompted to enter a <strong>Postback URL</strong>. This means that Branch does not already have a pre-configured postback template for that partner and you need to provide a valid URL for your partner. You can get this URL from the ad partner.</p><h2 id="disable-postbacks" tabindex="-1">Disable postbacks <a class="header-anchor" href="#disable-postbacks" aria-label="Permalink to &quot;Disable postbacks&quot;">​</a></h2><p>To disable any postback currently enabled for an ad partner:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to disable the postback(s).</li><li>Click on the <strong>Postback Config</strong> tab on said partner’s page.</li><li>Uncheck the box in the <strong>Enable</strong> column for the postback you want to disable.</li><li>Click <strong>Save</strong>.</li></ol><p><em>[Image: 885]</em></p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Branch runs weekly jobs to disable all non-functioning postbacks.</p><p>Any postback that has failed consistently over the last 7 days - throwing only 400/500 errors - will be automatically disabled.</p></div><h2 id="delete-postbacks" tabindex="-1">Delete postbacks <a class="header-anchor" href="#delete-postbacks" aria-label="Permalink to &quot;Delete postbacks&quot;">​</a></h2><p>To delete any postback currently added for an ad partner:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to delete postback(s) for.</li><li>Click on the <strong>Postback Config</strong> tab on said partner’s page.</li><li>Click the three dots icon to the right of the postback and click <strong>Delete Postback</strong>.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="sending-all-events" tabindex="-1">Sending all events <a class="header-anchor" href="#sending-all-events" aria-label="Permalink to &quot;Sending all events&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>As this setting will send <strong>All Events</strong> - with the name and customer event alias listed in this row, whether attributed to this partner or not - we recommend using caution when/if enabling, especially if you have enabled agencies to access your account.</p></div><p>If you want to send <strong>All Events</strong> you can enable this setting by checking the box on the <strong>All Events</strong> column on a per postback basis. When checked, all events will be sent regardless of attribution. Otherwise, the postback will only fire for events attributed to the ad partner.</p><h2 id="reset-postbacks" tabindex="-1">Reset postbacks <a class="header-anchor" href="#reset-postbacks" aria-label="Permalink to &quot;Reset postbacks&quot;">​</a></h2><p>There may be times when you need to reset a partner&#39;s settings; i.e. when a partner updates their postback templates or when perhaps you&#39;ve made a mistake during partner setup. Resetting a partner&#39;s settings allows you to re-enable the partner integration with the correct information to accurately measure and attribute conversion.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Resetting partner settings will:</p><ul><li>Disable the ad partner.</li><li>Clear out all of your saved credentials and postbacks that are already set up.</li><li>Return the ad partner to its basic configuration.</li></ul></div><p>To reset a specific partner&#39;s postbacks:</p><ol><li>Click on the <strong>Account Settings</strong> tab of the partner in question.</li><li>Click the <strong>Reset All Settings</strong> button in the right-hand corner.</li></ol><h2 id="allowlist-postback-ip-addresses" tabindex="-1">Allowlist postback IP addresses <a class="header-anchor" href="#allowlist-postback-ip-addresses" aria-label="Permalink to &quot;Allowlist postback IP addresses&quot;">​</a></h2><p>If required by your setup, allowlist the following postback server IP addresses for security purposes:</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>- 52.43.119.253/32 - 100.21.145.61/32 - 35.160.5.60/32 - 35.163.128.27/32 - 54.241.169.87/32 - 44.229.177.148/32 - 35.167.148.222/32 - 44.231.103.124/32 - 44.237.121.167/32 - 44.238.95.201/32 - 52.52.236.153/32</td><td>- 44.247.175.42/32 - 44.247.58.38/32 - 52.33.75.0/32 - 52.34.127.49/32 - 54.177.16.103/32 - 54.213.17.93/32 - 184.169.196.16/32 - 35.161.135.86/32 - 44.230.175.24/32 - 52.27.172.117/32 - 35.160.133.187/32</td></tr></tbody></table><h3 id="optional-configure-aws-security-group" tabindex="-1">Optional: Configure AWS security group <a class="header-anchor" href="#optional-configure-aws-security-group" aria-label="Permalink to &quot;Optional: Configure AWS security group&quot;">​</a></h3><p><strong>If you have an AWS account</strong> you use for webhooks, you will need to create a security group, as well as a series of inbound rules associated with that security group.</p><p>Note that this example <strong>does not include</strong> the entire list of IP addresses you need to make rules for. Find those <a href="./basic-postback-configuration.html#allowlist-postback-ip-addresses">above</a>.</p><h3 id="optional-configure-gcp-firewall-policy" tabindex="-1">Optional: Configure GCP firewall policy <a class="header-anchor" href="#optional-configure-gcp-firewall-policy" aria-label="Permalink to &quot;Optional: Configure GCP firewall policy&quot;">​</a></h3><p><strong>If you have an GCP account</strong> you use for webhooks, you will need to create a firewall policy, as well as a series of firewall rules associated with that policy.</p><p>Note that this example <strong>does not include</strong> the entire list of IP addresses you need to make rules for. Find those <a href="./basic-postback-configuration.html#allowlist-postback-ip-addresses">above</a>.</p>',35)])])}const b=t(r,[["render",n]]);export{u as __pageData,b as default};
